import java.util.*;
import java.util.concurrent.*;

// Simulating Redis-like cache with expiry
class SimpleCache<K, V> {
    record Entry<V>(V value, long expiresAt) {
        boolean isExpired() { return System.currentTimeMillis() > expiresAt; }
    }
    private final Map<K, Entry<V>> store = new ConcurrentHashMap<>();

    public void put(K key, V value, long ttlMs) {
        store.put(key, new Entry<>(value, System.currentTimeMillis() + ttlMs));
    }
    public Optional<V> get(K key) {
        Entry<V> e = store.get(key);
        if (e == null || e.isExpired()) { store.remove(key); return Optional.empty(); }
        return Optional.of(e.value());
    }
}

// Simulating DB
class UserDatabase {
    private int queryCount = 0;
    public Map<String,Object> findUser(long id) {
        queryCount++;
        System.out.println("[DB] Query #" + queryCount + " for user " + id);
        return Map.of("id", id, "name", "User#" + id, "email", "user" + id + "@example.com");
    }
    public int getQueryCount() { return queryCount; }
}

// Cache-aside pattern (most common)
class UserService {
    private final SimpleCache<Long, Map<String,Object>> cache = new SimpleCache<>();
    private final UserDatabase db = new UserDatabase();
    private static final long TTL_MS = 5 * 60 * 1000; // 5 minutes

    public Map<String,Object> getUser(long id) {
        // 1. Check cache
        return cache.get(id).orElseGet(() -> {
            // 2. Cache miss → query DB
            Map<String,Object> user = db.findUser(id);
            // 3. Populate cache
            cache.put(id, user, TTL_MS);
            return user;
        });
    }

    public void updateUser(long id, String name) {
        // Update DB, then invalidate cache (or update cache)
        System.out.println("[DB] Updated user " + id);
        cache.put(id, Map.of("id", id, "name", name), TTL_MS); // update
    }
}

public class CacheDemo {
    public static void main(String[] args) {
        UserService svc = new UserService();
        svc.getUser(1);    // DB query
        svc.getUser(1);    // cache hit — no DB
        svc.getUser(2);    // DB query
        svc.getUser(1);    // cache hit
        svc.getUser(2);    // cache hit
        // DB only queried twice for 5 calls
    }
}

import java.util.*;
import java.util.concurrent.atomic.*;

class Server {
    final String id;
    final AtomicInteger activeConnections = new AtomicInteger(0);
    Server(String id) { this.id = id; }
    String handle(String request) {
        activeConnections.incrementAndGet();
        String result = "[" + id + "] handled: " + request;
        activeConnections.decrementAndGet();
        return result;
    }
    @Override public String toString() { return id + "(conn=" + activeConnections + ")"; }
}

// Round Robin — simplest, assumes equal server capacity
class RoundRobinLB {
    private final List<Server> servers;
    private final AtomicInteger idx = new AtomicInteger(0);
    RoundRobinLB(List<Server> servers) { this.servers = servers; }
    public Server next() {
        return servers.get(idx.getAndIncrement() % servers.size());
    }
}

// Least Connections — routes to server with fewest active requests
class LeastConnectionLB {
    private final List<Server> servers;
    LeastConnectionLB(List<Server> servers) { this.servers = servers; }
    public Server next() {
        return servers.stream()
            .min(Comparator.comparingInt(s -> s.activeConnections.get()))
            .orElseThrow();
    }
}

public class LoadBalancerDemo {
    public static void main(String[] args) {
        List<Server> servers = List.of(new Server("S1"), new Server("S2"), new Server("S3"));

        RoundRobinLB rrLB = new RoundRobinLB(servers);
        System.out.println("=== Round Robin ===");
        for (int i = 1; i <= 6; i++)
            System.out.println(rrLB.next().handle("req-" + i));
        // S1, S2, S3, S1, S2, S3

        LeastConnectionLB lcLB = new LeastConnectionLB(new ArrayList<>(servers));
        System.out.println("\n=== Least Connections ===");
        System.out.println(lcLB.next().handle("req-a")); // goes to S1 (all equal → first)
    }
}

problems.description:
Implement an LRU (Least Recently Used) cache with O(1) get and put operations.

```java
public class LRUCache {
    private final int capacity;
    private final Map<Integer, Node> map = new HashMap<>();
    private final Node head = new Node(0,0), tail = new Node(0,0);
    // head <-> [most recent] <-> ... <-> [least recent] <-> tail

    public int get(int key) {
        Node n = map.get(key);
        if (n == null) return -1;
        moveToFront(n); return n.val;
    }
    public void put(int key, int val) {
        if (map.containsKey(key)) { map.get(key).val = val; moveToFront(map.get(key)); return; }
        if (map.size() == capacity) { map.remove(tail.prev.key); remove(tail.prev); }
        Node n = new Node(key, val);
        map.put(key, n); addToFront(n);
    }
}
```

**Example:**
LRU(2): put(1,1), put(2,2), get(1)→1, put(3,3) [evicts key 2], get(2)→-1

**Key insight:** HashMap for O(1) lookup + doubly-linked list for O(1) move-to-front and eviction. Java `LinkedHashMap` does this automatically.

