import java.util.*;

public class Q2 {
    static class RateLimiter {
        private final int maxRequests;
        private final long windowMs;
        private final Map<String, long[]> state = new HashMap<>(); // [count, windowStart]

        RateLimiter(int maxRequests, long windowMs) {
            this.maxRequests = maxRequests; this.windowMs = windowMs;
        }

        public synchronized boolean allow(String userId) {
            long now = System.currentTimeMillis();
            long[] data = state.computeIfAbsent(userId, k -> new long[]{0, now});
            if (now - data[1] >= windowMs) { data[0] = 0; data[1] = now; } // new window
            if (data[0] >= maxRequests) return false;
            data[0]++;
            return true;
        }
    }

    public static void main(String[] args) throws InterruptedException {
        RateLimiter rl = new RateLimiter(3, 1000);
        System.out.println(rl.allow("alice")); // true
        System.out.println(rl.allow("alice")); // true
        System.out.println(rl.allow("alice")); // true
        System.out.println(rl.allow("alice")); // false
        Thread.sleep(1100);
        System.out.println(rl.allow("alice")); // true
    }
}

problems.description:
Implement Consistent Hashing to distribute keys across servers.

```java
public class ConsistentHashRing {
    private final TreeMap<Long, String> ring = new TreeMap<>();
    private final int virtualNodes;

    public void addServer(String server) {
        for (int i = 0; i < virtualNodes; i++) {
            long hash = hash(server + "#" + i);
            ring.put(hash, server);
        }
    }
    public String getServer(String key) {
        long hash = hash(key);
        Map.Entry<Long, String> entry = ring.ceilingEntry(hash);
        return entry != null ? entry.getValue() : ring.firstEntry().getValue();
    }
    private long hash(String s) {
        return (long)s.hashCode() & 0xFFFFFFFFL; // unsigned 32-bit
    }
}
```

**Key insight:** Adding/removing a server only remaps ~1/N keys (not all keys). Virtual nodes ensure even distribution. Used by Cassandra, Redis Cluster, CDNs.

