import java.util.*;

public class Q3 {
    static class ConsistentHash {
        private final TreeMap<Integer, String> ring = new TreeMap<>();
        private final int virtualNodes;
        ConsistentHash(int vn) { this.virtualNodes = vn; }

        public void addServer(String server) {
            for (int i = 0; i < virtualNodes; i++)
                ring.put(hash(server + "#" + i), server);
        }

        public void removeServer(String server) {
            for (int i = 0; i < virtualNodes; i++)
                ring.remove(hash(server + "#" + i));
        }

        public String getServer(String key) {
            if (ring.isEmpty()) return null;
            int h = hash(key);
            Map.Entry<Integer,String> e = ring.ceilingEntry(h);
            return (e != null ? e : ring.firstEntry()).getValue();
        }

        private int hash(String s) { return Math.abs(s.hashCode()) % 3600; }
    }

    public static void main(String[] args) {
        ConsistentHash ch = new ConsistentHash(3);
        ch.addServer("S1"); ch.addServer("S2"); ch.addServer("S3");
        System.out.println(ch.getServer("user:alice"));
        System.out.println(ch.getServer("user:bob"));
        ch.removeServer("S2");
        System.out.println("After removing S2: " + ch.getServer("user:alice"));
    }
}
